func capturedImplementationRequests(stub *executeCapturingStub) []agentlib.ServiceExecuteRequest {
	stub.mu.Lock()
	defer stub.mu.Unlock()
	out := make([]agentlib.ServiceExecuteRequest, 0, len(stub.requests))
